const response = $input.first().json;
const reviews = response.result?.reviews || [];
const businessName = $('Business Configuration').first().json.businessName;
const ownerEmail = $('Business Configuration').first().json.ownerEmail;

// Get the static data to track which reviews we've already processed
const staticData = $getWorkflowStaticData('global');
const processedReviews = staticData.processedReviews || [];

// Filter to only new reviews we haven't seen
const newReviews = reviews.filter(review => {
  // Create a unique ID from author + time
  const reviewId = `${review.author_name}_${review.time}`;
  return !processedReviews.includes(reviewId);
});

// Mark all current reviews as processed
const allReviewIds = reviews.map(r => `${r.author_name}_${r.time}`);
staticData.processedReviews = allReviewIds;

if (newReviews.length === 0) {
  // Return empty to stop the workflow
  return [];
}

// Return each new review as a separate item
return newReviews.map(review => ({
  json: {
    authorName: review.author_name,
    rating: review.rating,
    text: review.text || '(No text)',
    relativeTime: review.relative_time_description,
    time: review.time,
    profilePhoto: review.profile_photo_url || '',
    sentiment: review.rating >= 4 ? 'positive' : review.rating === 3 ? 'neutral' : 'negative',
    businessName: businessName,
    ownerEmail: ownerEmail
  }
}));

