const item = $input.first().json;
const reviewData = $('Filter New Reviews Only').first().json;
let parsed;

try {
  parsed = JSON.parse(item.message.content);
} catch (e) {
  const match = item.message.content.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : { response: item.message.content, urgency: 'medium', actionNeeded: 'Review AI response' };
}

return [{
  json: {
    ...reviewData,
    suggestedResponse: parsed.response,
    urgency: parsed.urgency,
    actionNeeded: parsed.actionNeeded
  }
}];

